export interface IndustryPackQuestion {
  id: string;
  dimension: string;
  text: string;
  regulatoryRef: string;
  l1: string;
  l3: string;
  l5: string;
  weight: number;
}

export interface IndustryPack {
  id: IndustryPackId;
  stationId: Domain;
  name: string;
  description: string;
  regulatoryBasis: string[];
  questions: IndustryPackQuestion[];
  certificationThreshold: number;
  complianceFrameworks: string[];
  riskTier: "critical" | "very-high" | "high" | "elevated";
  euAIActClassification: string;
  sdgAlignment: string[];
  certificationPath: string;
  keyRisks: string[];
}

export interface IndustryPackAssessment {
  packId: IndustryPackId;
  responses: Record<string, number>;
}

// IndustryPackScoreResult is defined later in the functions section.

// ---------------------------------------------------------------------------
// Helper to build packs
// ---------------------------------------------------------------------------

function q(
  id: string,
  dimension: string,
  text: string,
  regulatoryRef: string,
  l1: string,
  l3: string,
  l5: string,
  weight: number
): IndustryPackQuestion {
  return { id, dimension, text, regulatoryRef, l1, l3, l5, weight };
}

